import{_ as e,c as i,o,ag as r}from"./chunks/framework.BRWBV1zN.js";const h=JSON.parse('{"title":"Visibilidad del Decodificador","description":"","frontmatter":{},"headers":[],"relativePath":"computer/cpu/decoder-visibility.md","filePath":"computer/cpu/decoder-visibility.md","lastUpdated":1780839004000}'),s={name:"computer/cpu/decoder-visibility.md"};function n(t,a,l,d,c,u){return o(),i("div",null,a[0]||(a[0]=[r(`<h1 id="visibilidad-del-decodificador" tabindex="-1">Visibilidad del Decodificador <a class="header-anchor" href="#visibilidad-del-decodificador" aria-label="Permalink to &quot;Visibilidad del Decodificador&quot;">​</a></h1><p>El decodificador de la unidad de control ha sido mejorado para ser más visible y proporcionar mejor retroalimentación visual durante la ejecución de programas.</p><h2 id="🎯-mejoras-de-visibilidad" tabindex="-1">🎯 Mejoras de Visibilidad <a class="header-anchor" href="#🎯-mejoras-de-visibilidad" aria-label="Permalink to &quot;🎯 Mejoras de Visibilidad&quot;">​</a></h2><h3 id="diseno-visual-mejorado" tabindex="-1">Diseño Visual Mejorado <a class="header-anchor" href="#diseno-visual-mejorado" aria-label="Permalink to &quot;Diseño Visual Mejorado&quot;">​</a></h3><ul><li><strong>Borde destacado</strong>: Borde verde brillante (<code>border-mantis-500</code>) que hace el decodificador más visible</li><li><strong>Sombra con efecto</strong>: Sombra verde que crea un efecto de profundidad y destaque</li><li><strong>Gradientes</strong>: Fondo con gradiente que mejora la apariencia visual</li><li><strong>Tipografía mejorada</strong>: Texto con sombra y efectos de brillo</li></ul><h3 id="indicadores-de-actividad" tabindex="-1">Indicadores de Actividad <a class="header-anchor" href="#indicadores-de-actividad" aria-label="Permalink to &quot;Indicadores de Actividad&quot;">​</a></h3><ul><li><strong>Punto pulsante</strong>: Un punto verde que parpadea cuando el decodificador está activo</li><li><strong>Animación de pulso</strong>: Todo el contenedor pulsa suavemente durante la ejecución</li><li><strong>Barra de progreso mejorada</strong>: Barra más alta y con gradiente para mejor visibilidad</li></ul><h3 id="botones-interactivos" tabindex="-1">Botones Interactivos <a class="header-anchor" href="#botones-interactivos" aria-label="Permalink to &quot;Botones Interactivos&quot;">​</a></h3><ul><li><strong>Efectos hover</strong>: Los botones se agrandan y brillan al pasar el mouse</li><li><strong>Transiciones suaves</strong>: Animaciones fluidas para mejor experiencia de usuario</li><li><strong>Colores distintivos</strong>: Botón verde (+) para memoria de control, azul (⚙️) para secuenciador</li></ul><h2 id="🔍-como-identificar-el-decodificador" tabindex="-1">🔍 Cómo Identificar el Decodificador <a class="header-anchor" href="#🔍-como-identificar-el-decodificador" aria-label="Permalink to &quot;🔍 Cómo Identificar el Decodificador&quot;">​</a></h2><h3 id="ubicacion" tabindex="-1">Ubicación <a class="header-anchor" href="#ubicacion" aria-label="Permalink to &quot;Ubicación&quot;">​</a></h3><p>El decodificador se encuentra en la <strong>unidad de control</strong> de la CPU, ubicada en la parte inferior izquierda del simulador.</p><h3 id="caracteristicas-visuales" tabindex="-1">Características Visuales <a class="header-anchor" href="#caracteristicas-visuales" aria-label="Permalink to &quot;Características Visuales&quot;">​</a></h3><ol><li><strong>Contenedor principal</strong>: Rectángulo con borde verde brillante</li><li><strong>Etiqueta</strong>: &quot;DECODIFICADOR&quot; en texto verde con sombra</li><li><strong>Barra de progreso</strong>: Barra verde que se llena durante la decodificación</li><li><strong>Botones</strong>: Botón cuadrado (+/-) para memoria de control y botón circular (⚙️) para secuenciador</li><li><strong>Memoria de control desplegable</strong>: Sección que aparece/desaparece con animación suave</li></ol><h3 id="estados-del-decodificador" tabindex="-1">Estados del Decodificador <a class="header-anchor" href="#estados-del-decodificador" aria-label="Permalink to &quot;Estados del Decodificador&quot;">​</a></h3><h4 id="estado-inactivo" tabindex="-1">Estado Inactivo <a class="header-anchor" href="#estado-inactivo" aria-label="Permalink to &quot;Estado Inactivo&quot;">​</a></h4><ul><li>Borde verde sin animación</li><li>Sin punto pulsante</li><li>Barra de progreso vacía</li><li>Texto &quot;Esperando...&quot; o &quot;CPU detenida&quot;</li></ul><h4 id="estado-activo" tabindex="-1">Estado Activo <a class="header-anchor" href="#estado-activo" aria-label="Permalink to &quot;Estado Activo&quot;">​</a></h4><ul><li>Borde verde con animación de pulso</li><li>Punto verde pulsante junto al texto</li><li>Barra de progreso que se llena</li><li>Nombre de la instrucción actual visible</li><li>Memoria de control desplegable (si está activada)</li></ul><h2 id="🎮-como-usar" tabindex="-1">🎮 Cómo Usar <a class="header-anchor" href="#🎮-como-usar" aria-label="Permalink to &quot;🎮 Cómo Usar&quot;">​</a></h2><h3 id="ejecutar-un-programa" tabindex="-1">Ejecutar un Programa <a class="header-anchor" href="#ejecutar-un-programa" aria-label="Permalink to &quot;Ejecutar un Programa&quot;">​</a></h3><ol><li><strong>Cargar programa</strong>: Abre un archivo .asm en el editor</li><li><strong>Compilar</strong>: Haz clic en &quot;Compilar&quot; para generar el código máquina</li><li><strong>Ejecutar</strong>: Haz clic en &quot;Ejecutar&quot; para comenzar la simulación</li><li><strong>Observar</strong>: El decodificador se volverá visible y activo</li></ol><h3 id="acceder-a-componentes-adicionales" tabindex="-1">Acceder a Componentes Adicionales <a class="header-anchor" href="#acceder-a-componentes-adicionales" aria-label="Permalink to &quot;Acceder a Componentes Adicionales&quot;">​</a></h3><ol><li><strong>Memoria de Control</strong>: Haz clic en el botón <strong>&quot;+&quot;</strong> para desplegar/ocultar dentro del decodificador</li><li><strong>Secuenciador</strong>: Haz clic en el botón <strong>&quot;⚙️&quot;</strong> azul para abrir el modal del secuenciador</li><li><strong>Cerrar</strong>: Para la memoria de control, haz clic en <strong>&quot;-&quot;</strong>; para el secuenciador, haz clic fuera del modal</li></ol><h2 id="📊-informacion-mostrada" tabindex="-1">📊 Información Mostrada <a class="header-anchor" href="#📊-informacion-mostrada" aria-label="Permalink to &quot;📊 Información Mostrada&quot;">​</a></h2><h3 id="durante-la-ejecucion" tabindex="-1">Durante la Ejecución <a class="header-anchor" href="#durante-la-ejecucion" aria-label="Permalink to &quot;Durante la Ejecución&quot;">​</a></h3><ul><li><strong>Nombre de la instrucción</strong>: Ej. &quot;MOV&quot;, &quot;ADD&quot;, &quot;JMP&quot;</li><li><strong>Operandos</strong>: Registros y valores involucrados</li><li><strong>Progreso</strong>: Barra que indica el avance de la decodificación</li><li><strong>Estado</strong>: Indicador visual de actividad</li></ul><h3 id="ejemplos-de-visualizacion" tabindex="-1">Ejemplos de Visualización <a class="header-anchor" href="#ejemplos-de-visualizacion" aria-label="Permalink to &quot;Ejemplos de Visualización&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DECODIFICADOR ● [██████████] 100%</span></span>
<span class="line"><span>MOV AL, 5</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DECODIFICADOR ● [██████░░░░] 60%</span></span>
<span class="line"><span>ADD AL, BL</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DECODIFICADOR   [░░░░░░░░░░] 0%</span></span>
<span class="line"><span>Esperando...</span></span></code></pre></div><h2 id="🔧-implementacion-tecnica" tabindex="-1">🔧 Implementación Técnica <a class="header-anchor" href="#🔧-implementacion-tecnica" aria-label="Permalink to &quot;🔧 Implementación Técnica&quot;">​</a></h2><h3 id="css-classes-utilizadas" tabindex="-1">CSS Classes Utilizadas <a class="header-anchor" href="#css-classes-utilizadas" aria-label="Permalink to &quot;CSS Classes Utilizadas&quot;">​</a></h3><ul><li><code>border-mantis-500</code>: Borde verde brillante</li><li><code>shadow-lg shadow-mantis-500/20</code>: Sombra con efecto verde</li><li><code>animate-pulse</code>: Animación de pulso</li><li><code>drop-shadow</code>: Efecto de sombra en texto</li><li><code>bg-gradient-to-r</code>: Gradientes de fondo</li></ul><h3 id="estados-reactivos" tabindex="-1">Estados Reactivos <a class="header-anchor" href="#estados-reactivos" aria-label="Permalink to &quot;Estados Reactivos&quot;">​</a></h3><ul><li><strong>cycle.phase</strong>: Determina si el decodificador está activo</li><li><strong>cycle.metadata</strong>: Proporciona información de la instrucción actual</li><li><strong>showControlMemory/showSequencer</strong>: Controlan la visibilidad de modales</li></ul><h3 id="animaciones" tabindex="-1">Animaciones <a class="header-anchor" href="#animaciones" aria-label="Permalink to &quot;Animaciones&quot;">​</a></h3><ul><li><strong>Pulso</strong>: Cuando <code>cycle.phase !== &quot;stopped&quot;</code></li><li><strong>Punto activo</strong>: Indicador visual de actividad</li><li><strong>Hover effects</strong>: Interacciones con botones</li><li><strong>Transiciones</strong>: Cambios suaves entre estados</li></ul><h2 id="🎓-beneficios-educativos" tabindex="-1">🎓 Beneficios Educativos <a class="header-anchor" href="#🎓-beneficios-educativos" aria-label="Permalink to &quot;🎓 Beneficios Educativos&quot;">​</a></h2><h3 id="comprension-visual" tabindex="-1">Comprensión Visual <a class="header-anchor" href="#comprension-visual" aria-label="Permalink to &quot;Comprensión Visual&quot;">​</a></h3><ul><li><strong>Identificación clara</strong>: Fácil de encontrar y reconocer</li><li><strong>Estado visible</strong>: Se puede ver cuándo está trabajando</li><li><strong>Progreso observable</strong>: Barra de progreso muestra el avance</li></ul><h3 id="interactividad" tabindex="-1">Interactividad <a class="header-anchor" href="#interactividad" aria-label="Permalink to &quot;Interactividad&quot;">​</a></h3><ul><li><strong>Componentes adicionales</strong>: Acceso fácil a memoria de control y secuenciador</li><li><strong>Retroalimentación inmediata</strong>: Cambios visuales instantáneos</li><li><strong>Experiencia mejorada</strong>: Interfaz más atractiva y profesional</li></ul><h3 id="aprendizaje" tabindex="-1">Aprendizaje <a class="header-anchor" href="#aprendizaje" aria-label="Permalink to &quot;Aprendizaje&quot;">​</a></h3><ul><li><strong>Conceptos claros</strong>: Visualización de la decodificación de instrucciones</li><li><strong>Proceso observable</strong>: Se puede ver el trabajo interno de la CPU</li><li><strong>Integración</strong>: Conexión visual entre instrucciones y microoperaciones</li></ul><h2 id="🚀-casos-de-uso" tabindex="-1">🚀 Casos de Uso <a class="header-anchor" href="#🚀-casos-de-uso" aria-label="Permalink to &quot;🚀 Casos de Uso&quot;">​</a></h2><h3 id="para-estudiantes" tabindex="-1">Para Estudiantes <a class="header-anchor" href="#para-estudiantes" aria-label="Permalink to &quot;Para Estudiantes&quot;">​</a></h3><ol><li><strong>Identificar componentes</strong>: Aprender a reconocer partes de la CPU</li><li><strong>Entender procesos</strong>: Ver cómo se decodifican las instrucciones</li><li><strong>Seguir ejecución</strong>: Observar el progreso de cada instrucción</li></ol><h3 id="para-educadores" tabindex="-1">Para Educadores <a class="header-anchor" href="#para-educadores" aria-label="Permalink to &quot;Para Educadores&quot;">​</a></h3><ol><li><strong>Demostración</strong>: Mostrar el funcionamiento interno de la CPU</li><li><strong>Explicación</strong>: Usar la visualización para explicar conceptos</li><li><strong>Evaluación</strong>: Verificar que los estudiantes entienden el proceso</li></ol><h3 id="para-desarrolladores" tabindex="-1">Para Desarrolladores <a class="header-anchor" href="#para-desarrolladores" aria-label="Permalink to &quot;Para Desarrolladores&quot;">​</a></h3><ol><li><strong>Debugging</strong>: Entender qué instrucción se está procesando</li><li><strong>Optimización</strong>: Ver el impacto de diferentes tipos de instrucciones</li><li><strong>Desarrollo</strong>: Usar como referencia para implementar mejoras</li></ol><p>Esta implementación hace que el decodificador sea mucho más visible y útil para el aprendizaje y la comprensión de la arquitectura de computadoras.</p>`,53)]))}const m=e(s,[["render",n]]);export{h as __pageData,m as default};
